// ============================================================
// FORMAT DATA — DYNAMIC VERSION
// Otomatis membaca header apapun dari Google Sheets
// Tidak perlu diubah meski kolom bertambah atau berganti nama
// ============================================================

const items = $input.all();

// Validasi: pastikan ada data
if (!items || items.length === 0) {
  throw new Error('Sheet kosong atau tidak ada data yang dibaca.');
}

// 1. Deteksi header secara otomatis dari baris pertama
const headers = Object.keys(items[0].json);

if (headers.length === 0) {
  throw new Error('Tidak ada kolom yang terdeteksi di sheet.');
}

// 2. Bangun tabel Markdown secara dinamis
const headerRow = '| ' + headers.join(' | ') + ' |';
const divider   = '| ' + headers.map(() => '---').join(' | ') + ' |';

const bodyRows = items.map(item => {
  const row = item.json;
  const cells = headers.map(h => {
    const val = row[h];
    return (val !== null && val !== undefined && val !== '') ? String(val) : '-';
  });
  return '| ' + cells.join(' | ') + ' |';
}).join('\n');

const markdownTable = [headerRow, divider, bodyRows].join('\n');

// 3. Hitung statistik numerik otomatis untuk SEMUA kolom angka
const numericStats = {};
headers.forEach(h => {
  const values = items
    .map(item => parseFloat(String(item.json[h]).replace(/[^0-9.-]/g, '')))
    .filter(v => !isNaN(v));

  if (values.length > 0) {
    const sum = values.reduce((a, b) => a + b, 0);
    numericStats[h] = {
      total: sum,
      rata_rata: sum / values.length,
      tertinggi: Math.max(...values),
      terendah: Math.min(...values),
      jumlah_baris: values.length
    };
  }
});

// 4. Buat ringkasan statistik dalam format teks untuk prompt AI
let statsSummary = '';
Object.entries(numericStats).forEach(([kolom, stat]) => {
  statsSummary += `\n- **${kolom}**: Total = ${stat.total.toLocaleString('id-ID')}, Rata-rata = ${stat.rata_rata.toLocaleString('id-ID')}, Tertinggi = ${stat.tertinggi.toLocaleString('id-ID')}, Terendah = ${stat.terendah.toLocaleString('id-ID')}`;
});

// 5. Metadata
const bulan = new Date().toLocaleDateString('id-ID', { month: 'long', year: 'numeric' });
const spreadsheetName = 'cashflow_AI_report';

return {
  markdown_table: markdownTable,
  headers: headers,
  jumlah_kolom: headers.length,
  jumlah_baris: items.length,
  numeric_stats: numericStats,
  stats_summary: statsSummary || 'Tidak ada kolom numerik terdeteksi.',
  spreadsheet_name: spreadsheetName,
  bulan: bulan
};

